import React, { useState } from 'react';
import {
  Card,
  CardContent,
  CardActions,
  Button,
  Stack,
  Box,
  Chip,
  Typography,
  IconButton,
  Tooltip,
} from '@mui/material';
import BookmarkBorderIcon from '@mui/icons-material/BookmarkBorder';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import { useNavigate } from 'react-router-dom';

const JobCard = ({
  job,
  isSaved = false,
  onSave,
  onUnsave,
  applicationStatus,
}) => {
  const navigate = useNavigate();
  const [isJobSaved, setIsJobSaved] = useState(isSaved);

  const handleSave = () => {
    if (isJobSaved) {
      onUnsave(job._id);
      setIsJobSaved(false);
    } else {
      onSave(job._id);
      setIsJobSaved(true);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'accepted':
        return 'success';
      case 'rejected':
        return 'error';
      case 'pending':
      case 'reviewed':
        return 'warning';
      case 'applied':
        return 'info';
      default:
        return 'default';
    }
  };

  return (
    <Card sx={{ mb: 2, '&:hover': { boxShadow: 3 } }}>
      <CardContent>
        <Stack spacing={1} sx={{ mb: 2 }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <Box sx={{ flex: 1 }}>
              <Typography variant="h6" sx={{ fontWeight: 600 }}>
                {job.title}
              </Typography>
              <Typography variant="body2" color="textSecondary">
                {job.company}
              </Typography>
            </Box>
            <Tooltip title={isJobSaved ? 'Remove from saved' : 'Save job'}>
              <IconButton
                size="small"
                onClick={handleSave}
                sx={{ ml: 1 }}
              >
                {isJobSaved ? (
                  <BookmarkIcon color="primary" />
                ) : (
                  <BookmarkBorderIcon />
                )}
              </IconButton>
            </Tooltip>
          </Box>

          {/* Job Details */}
          <Stack direction="row" spacing={1} sx={{ flexWrap: 'wrap' }}>
            <Chip
              label={job.location}
              variant="outlined"
              size="small"
            />
            <Chip
              label={job.jobType}
              variant="outlined"
              size="small"
              color="primary"
            />
            {job.experienceLevel && (
              <Chip
                label={job.experienceLevel}
                variant="outlined"
                size="small"
              />
            )}
          </Stack>

          {/* Salary */}
          {job.salary && (
            <Typography variant="body2" sx={{ fontWeight: 500 }}>
              {job.salary}
            </Typography>
          )}

          {/* Description Preview */}
          <Typography variant="body2" color="textSecondary" sx={{ mt: 1 }}>
            {job.description.substring(0, 150)}...
          </Typography>

          {/* Application Status */}
          {applicationStatus && (
            <Box sx={{ mt: 2 }}>
              <Chip
                label={`Application: ${applicationStatus}`}
                color={getStatusColor(applicationStatus)}
                variant="filled"
                size="small"
              />
            </Box>
          )}
        </Stack>
      </CardContent>

      <CardActions>
        <Button
          size="small"
          color="primary"
          onClick={() => navigate(`/jobs/${job._id}`)}
        >
          View Details
        </Button>
      </CardActions>
    </Card>
  );
};

export default JobCard;
