import React, { useEffect, useState, useContext } from 'react';
import { Container, Box, Typography, Grid, Card, CardContent, Button, CircularProgress, Alert } from '@mui/material';
import { useNavigate } from 'react-router-dom';
import DescriptionIcon from '@mui/icons-material/Description';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import PersonIcon from '@mui/icons-material/Person';
import { usersAPI, jobsAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';

const DashboardPage = () => {
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [userData, setUserData] = useState(null);
  const [userJobs, setUserJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      setError(null);

      // Fetch user profile
      const userRes = await usersAPI.getUserProfile();
      setUserData(userRes.data);

      // Fetch user's jobs (for employers)
      if (userRes.data.userType === 'employer') {
        const jobsRes = await jobsAPI.getUserJobs();
        setUserJobs(jobsRes.data);
      }
    } catch (err) {
      console.error('Failed to fetch dashboard data:', err);
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
          <CircularProgress />
        </Box>
      </Container>
    );
  }

  const stats = [
    {
      icon: <DescriptionIcon sx={{ fontSize: 40, color: '#667eea' }} />,
      label: 'My Applications',
      value: '0',
      color: '#667eea',
    },
    {
      icon: <BookmarkIcon sx={{ fontSize: 40, color: '#764ba2' }} />,
      label: 'Saved Jobs',
      value: '0',
      color: '#764ba2',
    },
    {
      icon: <PersonIcon sx={{ fontSize: 40, color: '#f093fb' }} />,
      label: 'Job Posts',
      value: userData?.userType === 'employer' ? userJobs.length : '0',
      color: '#f093fb',
    },
  ];

  return (
    <Container maxWidth="lg">
      <Typography variant="h2" sx={{ mb: 4 }}>
        Dashboard
      </Typography>

      {error && <Alert severity="error" sx={{ mb: 3 }}>{error}</Alert>}

      {/* Stats Cards */}
      <Grid container spacing={3} sx={{ mb: 6 }}>
        {stats.map((stat, index) => (
          <Grid item xs={12} md={4} key={index}>
            <Card
              sx={{
                textAlign: 'center',
                py: 3,
                background: 'linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%)',
                border: '1px solid #e0e0e0',
              }}
            >
              <CardContent>
                <Box sx={{ mb: 2 }}>{stat.icon}</Box>
                <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 1 }}>
                  {stat.value}
                </Typography>
                <Typography variant="body2" color="textSecondary">
                  {stat.label}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {/* User Profile Section */}
      {userData && (
        <Card sx={{ mb: 4 }}>
          <CardContent sx={{ p: 3 }}>
            <Typography variant="h5" sx={{ fontWeight: 'bold', mb: 2 }}>
              My Profile
            </Typography>
            <Grid container spacing={2}>
              <Grid item xs={12} md={6}>
                <Typography variant="body2" color="textSecondary">
                  Name
                </Typography>
                <Typography variant="body1" sx={{ fontWeight: 500 }}>
                  {userData.firstName} {userData.lastName}
                </Typography>
              </Grid>
              <Grid item xs={12} md={6}>
                <Typography variant="body2" color="textSecondary">
                  Email
                </Typography>
                <Typography variant="body1" sx={{ fontWeight: 500 }}>
                  {userData.email}
                </Typography>
              </Grid>
              {userData.userType === 'employer' && userData.company && (
                <Grid item xs={12} md={6}>
                  <Typography variant="body2" color="textSecondary">
                    Company
                  </Typography>
                  <Typography variant="body1" sx={{ fontWeight: 500 }}>
                    {userData.company}
                  </Typography>
                </Grid>
              )}
              {userData.phone && (
                <Grid item xs={12} md={6}>
                  <Typography variant="body2" color="textSecondary">
                    Phone
                  </Typography>
                  <Typography variant="body1" sx={{ fontWeight: 500 }}>
                    {userData.phone}
                  </Typography>
                </Grid>
              )}
              {userData.bio && (
                <Grid item xs={12}>
                  <Typography variant="body2" color="textSecondary">
                    Bio
                  </Typography>
                  <Typography variant="body1">{userData.bio}</Typography>
                </Grid>
              )}
            </Grid>
          </CardContent>
        </Card>
      )}

      {/* Posted Jobs Section */}
      {userData?.userType === 'employer' && (
        <>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
            <Typography variant="h5" sx={{ fontWeight: 'bold' }}>
              My Posted Jobs
            </Typography>
            <Button
              variant="contained"
              sx={{
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              }}
              onClick={() => navigate('/post-job')}
            >
              Post New Job
            </Button>
          </Box>

          {userJobs.length > 0 ? (
            <Grid container spacing={2}>
              {userJobs.map((job) => (
                <Grid item xs={12} key={job._id}>
                  <Card>
                    <CardContent>
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                        <Box>
                          <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 1 }}>
                            {job.title}
                          </Typography>
                          <Typography variant="body2" color="textSecondary" sx={{ mb: 1 }}>
                            {job.location} • {job.jobType}
                          </Typography>
                          <Typography variant="caption" color="textSecondary">
                            Applications: {job.applications?.length || 0}
                          </Typography>
                        </Box>
                        <Box sx={{ display: 'flex', gap: 1 }}>
                          <Button
                            size="small"
                            variant="outlined"
                            onClick={() => navigate(`/edit-job/${job._id}`)}
                          >
                            Edit
                          </Button>
                          <Button
                            size="small"
                            variant="outlined"
                            color="error"
                            onClick={() => {
                              // Handle delete
                              alert('Delete functionality to be implemented');
                            }}
                          >
                            Delete
                          </Button>
                        </Box>
                      </Box>
                    </CardContent>
                  </Card>
                </Grid>
              ))}
            </Grid>
          ) : (
            <Card>
              <CardContent>
                <Typography variant="body1" sx={{ textAlign: 'center', py: 2 }}>
                  No jobs posted yet. Start by creating a new job posting!
                </Typography>
              </CardContent>
            </Card>
          )}
        </>
      )}

      {userData?.userType === 'job-seeker' && (
        <Card>
          <CardContent sx={{ textAlign: 'center', py: 4 }}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Ready to find your next opportunity?
            </Typography>
            <Button
              variant="contained"
              size="large"
              sx={{
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              }}
              onClick={() => navigate('/jobs')}
            >
              Browse Jobs
            </Button>
          </CardContent>
        </Card>
      )}
    </Container>
  );
};

export default DashboardPage;
