import React from 'react';
import { Container, Box, Typography, Button, Grid, Card, CardContent } from '@mui/material';
import { useNavigate } from 'react-router-dom';
import WorkIcon from '@mui/icons-material/Work';
import SearchIcon from '@mui/icons-material/Search';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';

const HomePage = () => {
  const navigate = useNavigate();

  const features = [
    {
      icon: <SearchIcon sx={{ fontSize: 40, color: '#667eea' }} />,
      title: 'Search Jobs',
      description: 'Find your perfect job from thousands of listings',
    },
    {
      icon: <WorkIcon sx={{ fontSize: 40, color: '#667eea' }} />,
      title: 'Post Jobs',
      description: 'Hire the best talent for your organization',
    },
    {
      icon: <TrendingUpIcon sx={{ fontSize: 40, color: '#667eea' }} />,
      title: 'Career Growth',
      description: 'Build your career with opportunities tailored for you',
    },
  ];

  return (
    <Container maxWidth="lg">
      {/* Hero Section */}
      <Box
        sx={{
          textAlign: 'center',
          py: 8,
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          borderRadius: 2,
          color: '#fff',
          mb: 6,
        }}
      >
        <Typography variant="h1" sx={{ color: '#fff', mb: 2 }}>
          Welcome to JobPortal
        </Typography>
        <Typography variant="h5" sx={{ mb: 4, opacity: 0.9 }}>
          Find your dream job or hire top talent today
        </Typography>
        <Box sx={{ display: 'flex', gap: 2, justifyContent: 'center' }}>
          <Button
            variant="contained"
            size="large"
            sx={{
              backgroundColor: '#fff',
              color: '#667eea',
              fontWeight: 'bold',
              '&:hover': { backgroundColor: 'rgba(255, 255, 255, 0.9)' },
            }}
            onClick={() => navigate('/jobs')}
          >
            Browse Jobs
          </Button>
          <Button
            variant="outlined"
            size="large"
            sx={{
              borderColor: '#fff',
              color: '#fff',
              '&:hover': { backgroundColor: 'rgba(255, 255, 255, 0.1)' },
            }}
            onClick={() => navigate('/post-job')}
          >
            Post a Job
          </Button>
        </Box>
      </Box>

      {/* Features Section */}
      <Box sx={{ mb: 8 }}>
        <Typography variant="h2" sx={{ textAlign: 'center', mb: 4 }}>
          Why Choose Us?
        </Typography>
        <Grid container spacing={3}>
          {features.map((feature, index) => (
            <Grid item xs={12} md={4} key={index}>
              <Card
                sx={{
                  height: '100%',
                  textAlign: 'center',
                  p: 3,
                  '&:hover': {
                    boxShadow: '0 8px 24px rgba(0, 0, 0, 0.15)',
                    transform: 'translateY(-4px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <CardContent>
                  <Box sx={{ mb: 2 }}>{feature.icon}</Box>
                  <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 1 }}>
                    {feature.title}
                  </Typography>
                  <Typography variant="body2" color="textSecondary">
                    {feature.description}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Box>
    </Container>
  );
};

export default HomePage;
